import { defineConfig, globalIgnores } from "eslint/config";
import nextVitals from "eslint-config-next/core-web-vitals";
import nextTs from "eslint-config-next/typescript";
import neostandard from "neostandard";
import tsPlugin from "@typescript-eslint/eslint-plugin";
import reactHooks from "eslint-plugin-react-hooks";
import jsxA11y from "eslint-plugin-jsx-a11y";
import vitest from "@vitest/eslint-plugin";
import tailwindcss from "eslint-plugin-tailwindcss";
import prettierConfig from "eslint-config-prettier";
import * as importX from "eslint-plugin-import-x";
import unusedImports from "eslint-plugin-unused-imports";
import unicorn from "eslint-plugin-unicorn";
import noRelativeImportPaths from "eslint-plugin-no-relative-import-paths";

const TEST_FILES = ["**/*.test.ts", "**/*.test.tsx"];

const NEXT_APP_ROUTER_FILES = [
  "^page\\.tsx?$",
  "^layout\\.tsx?$",
  "^loading\\.tsx?$",
  "^error\\.tsx?$",
  "^not-found\\.tsx?$",
  "^route\\.ts$",
  "^middleware\\.ts$",
  "^globals\\.css$",
  "^template\\.tsx?$",
  "^default\\.tsx?$",
  "^instrumentation\\.ts$",
];

const eslintConfig = defineConfig([
  // Next.js rules
  ...nextVitals,
  ...nextTs,

  // Base: neostandard (noStyle: true to let Prettier handle formatting)
  ...neostandard({ noStyle: true, ts: true }),

  // React hooks
  reactHooks.configs.flat.recommended,

  // Accessibility
  jsxA11y.flatConfigs.recommended,

  // Tailwind CSS quality rules
  tailwindcss.configs["flat/recommended"],

  // Import ordering and circular dependency detection
  importX.flatConfigs.recommended,
  importX.flatConfigs.typescript,

  // Custom rules
  {
    plugins: {
      "unused-imports": unusedImports,
      "no-relative-import-paths": noRelativeImportPaths,
    },
    rules: {
      // unused-imports replaces @typescript-eslint/no-unused-vars
      "@typescript-eslint/no-unused-vars": "off",
      "no-unused-vars": "off",
      "unused-imports/no-unused-imports": "error",
      "unused-imports/no-unused-vars": [
        "warn",
        {
          vars: "all",
          varsIgnorePattern: "^_",
          args: "after-used",
          argsIgnorePattern: "^_",
        },
      ],

      // Enforce absolute imports with @/ alias (same folder allowed)
      "no-relative-import-paths/no-relative-import-paths": [
        "error",
        { allowSameFolder: true, rootDir: ".", prefix: "@" },
      ],

      // Tailwind: class ordering handled by prettier-plugin-tailwindcss
      "tailwindcss/classnames-order": "off",

      // TypeScript additional rules
      "@typescript-eslint/consistent-type-imports": [
        "error",
        { prefer: "type-imports", fixStyle: "inline-type-imports" },
      ],
      "@typescript-eslint/consistent-type-definitions": ["error", "interface"],
      "@typescript-eslint/explicit-function-return-type": [
        "error",
        {
          allowExpressions: true,
          allowTypedFunctionExpressions: true,
          allowHigherOrderFunctions: true,
          allowDirectConstAssertionInArrowFunctions: true,
        },
      ],
      "@typescript-eslint/naming-convention": [
        "error",
        { selector: "default", format: ["camelCase"] },
        {
          selector: "variable",
          format: ["camelCase", "UPPER_CASE", "PascalCase"],
        },
        {
          selector: "parameter",
          format: ["camelCase"],
          leadingUnderscore: "allow",
        },
        { selector: "function", format: ["camelCase", "PascalCase"] },
        { selector: "typeLike", format: ["PascalCase"] },
        { selector: "enumMember", format: ["PascalCase", "UPPER_CASE"] },
        {
          selector: "objectLiteralProperty",
          format: null,
        },
        {
          selector: "import",
          format: ["camelCase", "PascalCase", "UPPER_CASE"],
        },
      ],
    },
  },

  // Unicorn: modern JS best practices and file naming
  {
    plugins: { unicorn },
    rules: {
      ...unicorn.configs["flat/recommended"].rules,
      // Allow existing filename conventions for Next.js App Router
      "unicorn/filename-case": [
        "error",
        {
          cases: { kebabCase: true },
          allow: NEXT_APP_ROUTER_FILES,
        },
      ],
      // Disable rules that are too opinionated for this project
      "unicorn/prevent-abbreviations": "off",
      "unicorn/no-null": "off",
      "unicorn/no-array-reduce": "off",
      "unicorn/no-array-for-each": "off",
    },
  },

  // Prettier: must be last to disable conflicting style rules
  prettierConfig,

  // Vitest rules for test files only
  {
    files: TEST_FILES,
    plugins: { vitest },
    rules: {
      ...vitest.configs.recommended.rules,
    },
  },

  globalIgnores([
    ".next/**",
    "out/**",
    "build/**",
    "next-env.d.ts",
    "coverage/**",
    "node_modules/**",
  ]),
]);

export default eslintConfig;

